def test_skips_when_yg_mcp_core_not_installed(session_dir: Path) -> None:
    # If the system python3 already has yg-mcp-core, skip — can't simulate
    # the dep-miss without a hermetic venv (most useful in CI on a fresh runner).
    probe = subprocess.run(
        ["python3", "-c", "import mcp_core.client"],
        capture_output=True,
        check=False,
    )
    if probe.returncode == 0:
        pytest.skip(
            "system python3 has mcp_core installed — can't simulate dep-miss "
            "without a hermetic venv (most useful in CI)"
        )

    _write_brainstorm(session_dir, _high_stakes_brainstorm())
    result = _run(session_dir)

    assert result.returncode == 0, f"stderr: {result.stderr}"
    assert "yg-mcp-core not importable" in result.stdout
    handoff = _load_handoff(session_dir)
    assert handoff["status"] == "skipped"
    assert "yg-mcp-core not importable" in handoff["skip_reason"]


