def test_fires_and_downloads_m4a_end_to_end(
    session_dir: Path, shim_succeeds: tuple[Path, str]
) -> None:
    shim_path, expected_url = shim_succeeds
    _write_brainstorm(session_dir, _high_stakes_brainstorm())
    result = _run(session_dir, pythonpath=shim_path)

    assert result.returncode == 0, f"stderr: {result.stderr}"
    assert "signal fired" in result.stdout
    assert "wrote" in result.stdout

    m4a_path = session_dir / "brainstorm-podcast.m4a"
    assert m4a_path.exists()
    assert m4a_path.stat().st_size > 0
    assert m4a_path.read_bytes().startswith(b"FAKE_M4A_BYTES_FOR_TEST")

    handoff = _load_handoff(session_dir)
    assert handoff["status"] == "fired"
    assert handoff["m4a_path"] == str(m4a_path)
    assert handoff["m4a_url"] == expected_url
    assert handoff["size_bytes"] == m4a_path.stat().st_size


